        expect(count).toBe(2);
        expect(db.size()).toBe(2);
        expect(db.get('first')).toBe('hello');
        expect(db.get('second')).toBe('there');
        expect(errors).toHaveLength(1);
      } catch (e) {
        fs.rmSync(tmpDir, { recursive: true, force: true });
        done(e);
        return;
      }
      db.close();
      db.once('write_close', () => {
        fs.rmSync(tmpDir, { recursive: true, force: true });
        done();
      });
    });
  }, 10000);
